import { createContext } from 'react';

// Called at module level, outside any component
const ThemeContext = createContext('light'); // 'light' is the default value

// ThemeContext.Provider — used to supply a value
// ThemeContext.Consumer — legacy API; use useContext instead
// ThemeContext.displayName — optional, for React DevTools

import { ThemeContext } from './ThemeContext';

function App() {
  return (
    <ThemeContext.Provider value="dark">
      {/* All descendants can read 'dark' via useContext(ThemeContext) */}
      <Header />
      <Main />
      <Footer />
    </ThemeContext.Provider>
  );
}

import { createContext, useState } from 'react';

export const ThemeContext = createContext(null);

export function ThemeProvider({ children }) {
  const [theme, setTheme] = useState('light');

  return (
    <ThemeContext.Provider value={{ theme, setTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}

// App wraps its tree with the provider:
function App() {
  return (
    <ThemeProvider>
      <Header />
      <Main />
    </ThemeProvider>
  );
}

// Option A: null default — clearly indicates 'no Provider present'
const UserContext = createContext(null);

// Option B: object default — works without a Provider, useful in tests
const UserContext = createContext({ user: null, login: () => {}, logout: () => {} });

// Option C: throw in useContext wrapper instead of using default
export function useUser() {
  const ctx = useContext(UserContext);
  if (ctx === null) throw new Error('useUser must be used inside UserProvider');
  return ctx;
}

// ✗ Wrong: new context object created every render
function BadComponent() {
  const BadContext = createContext(null); // new object each render!
  return <BadContext.Provider value={42}><Child /></BadContext.Provider>;
}

// ✓ Correct: context created once at module level
const GoodContext = createContext(null);

function GoodComponent() {
  return <GoodContext.Provider value={42}><Child /></GoodContext.Provider>;
}

const LevelContext = createContext(0);

function Section({ children }) {
  const level = useContext(LevelContext);
  return (
    <LevelContext.Provider value={level + 1}>
      {children}
    </LevelContext.Provider>
  );
}

// Usage:
// <Section>         ← LevelContext value: 0 + 1 = 1
//   <Section>       ← value: 1 + 1 = 2
//     <Section>     ← value: 2 + 1 = 3
//       <Heading /> ← reads level 3

// ThemeContext.js
import { createContext, useContext, useState } from 'react';

const ThemeContext = createContext(null); // NOT exported

export function ThemeProvider({ children }) {
  const [theme, setTheme] = useState('light');
  return (
    <ThemeContext.Provider value={{ theme, setTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}

export function useTheme() {
  const ctx = useContext(ThemeContext);
  if (!ctx) throw new Error('useTheme must be used within a ThemeProvider');
  return ctx;
}

// Consumer component:
import { useTheme } from './ThemeContext';

function ThemeToggle() {
  const { theme, setTheme } = useTheme();
  return (
    <button onClick={() => setTheme(t => t === 'light' ? 'dark' : 'light')}>
      Switch to {theme === 'light' ? 'dark' : 'light'}
    </button>
  );
}

import { createContext, useState, useMemo } from 'react';

const ThemeContext = createContext(null);

function App() {
  const [theme, setTheme] = useState('light');

  // Without useMemo: new object on every App render → all consumers re-render
  // With useMemo: same reference until 'theme' changes
  const value = useMemo(() => ({ theme, setTheme }), [theme]);

  return (
    <ThemeContext.Provider value={value}>
      <Tree />
    </ThemeContext.Provider>
  );
}

const ThemeContext   = createContext(null);
const AuthContext    = createContext(null);
const LocaleContext  = createContext('en');

function App() {
  const [theme, setTheme]   = useState('light');
  const [user, setUser]     = useState(null);
  const [locale, setLocale] = useState('en');

  return (
    <ThemeContext.Provider value={useMemo(() => ({ theme, setTheme }), [theme])}>
      <AuthContext.Provider value={useMemo(() => ({ user, setUser }), [user])}>
        <LocaleContext.Provider value={locale}>
          <Router />
        </LocaleContext.Provider>
      </AuthContext.Provider>
    </ThemeContext.Provider>
  );
}

function AppProviders({ children }) {
  return (
    <ThemeProvider>
      <AuthProvider>
        <LocaleProvider>
          {children}
        </LocaleProvider>
      </AuthProvider>
    </ThemeProvider>
  );
}

// App root:
function App() {
  return (
    <AppProviders>
      <Router />
    </AppProviders>
  );
}

const ThemeContext = createContext(null);
ThemeContext.displayName = 'ThemeContext'; // shown in React DevTools

// Without displayName: Context.Provider, Context.Consumer
// With displayName:    ThemeContext.Provider, ThemeContext.Consumer

// src/context/ThemeContext.jsx
import { createContext, useContext, useState, useMemo } from 'react';

const ThemeContext = createContext(null);
ThemeContext.displayName = 'ThemeContext';

export function ThemeProvider({ children }) {
  const [theme, setTheme] = useState('light');
  const value = useMemo(() => ({ theme, setTheme }), [theme]);
  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

export function useTheme() {
  const ctx = useContext(ThemeContext);
  if (!ctx) throw new Error('useTheme must be called inside ThemeProvider');
  return ctx;
}

// Consumers import only useTheme and ThemeProvider:
// import { ThemeProvider } from '../context/ThemeContext';
// import { useTheme }     from '../context/ThemeContext';

const CountContext = createContext(0);

function CountProvider({ children }) {
  const [count, setCount] = useState(0);
  return (
    <CountContext.Provider value={count}>
      {children}
    </CountContext.Provider>
  );
}

// count is a primitive — consumers re-render only when it changes
// If value were { count } (object): new ref on every Provider render,
// causing all consumers to re-render even when count hasn't changed

// Next.js: pass server-side initial value as a prop
export default function RootLayout({ children, initialTheme }) {
  return (
    <ThemeProvider initialTheme={initialTheme}>
      {children}
    </ThemeProvider>
  );
}

function ThemeProvider({ children, initialTheme = 'light' }) {
  const [theme, setTheme] = useState(initialTheme);
  const value = useMemo(() => ({ theme, setTheme }), [theme]);
  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}
